import type {
  A11yToolbarTabIndex,
  ToolbarInteractionModes,
} from '../../../types/toolbar.js';

/**
 * Get value from ToolbarTabIndex [key]: number
 *
 * @param tabIndex - toolbar control tab index [key]: number
 */
export function getTabIndexKey(
  tabIndex: A11yToolbarTabIndex,
): ToolbarInteractionModes {
  return Object.keys(tabIndex)[0] as ToolbarInteractionModes;
}
